/* eslint-disable @typescript-eslint/no-unused-vars */

// Generated by Claude Opus 4.6

import * as mockClient from '@kubernetes/client-node';
import { CoreV1Api, V1ConfigMap, V1ConfigMapList } from '@kubernetes/client-node';

import { AiRegistryApiService } from '@/devworkspaceClient/services/aiRegistryApi';
import { CoreV1API } from '@/devworkspaceClient/services/helpers/prepareCoreV1API';
import { logger } from '@/utils/logger';

jest.mock('@/devworkspaceClient/services/helpers/retryableExec.ts');

jest.mock('@/utils/logger', () => ({
  logger: {
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

const mockCoreV1Api = {
  listNamespacedConfigMap: jest.fn(),
};

jest.mock('@/devworkspaceClient/services/helpers/prepareCoreV1API', () => ({
  prepareCoreV1API: jest.fn(() => mockCoreV1Api),
}));

const namespace = 'eclipse-che';
const AI_REGISTRY_LABEL_SELECTOR =
  'app.kubernetes.io/component=ai-tool-registry,app.kubernetes.io/part-of=che.eclipse.org';

const EMPTY_REGISTRY = {
  providers: [],
  tools: [],
  defaultAiProviders: [],
};

describe('AI Registry API Service', () => {
  let service: AiRegistryApiService;
  const originalEnv = process.env;

  beforeEach(() => {
    process.env = { ...originalEnv, CHECLUSTER_CR_NAMESPACE: namespace };

    const { KubeConfig } = mockClient;
    const kubeConfig = new KubeConfig();
    service = new AiRegistryApiService(kubeConfig);
  });

  afterEach(() => {
    process.env = originalEnv;
    jest.clearAllMocks();
  });

  describe('get', () => {
    it('should return empty registry when CHECLUSTER_CR_NAMESPACE is not set', async () => {
      delete process.env.CHECLUSTER_CR_NAMESPACE;

      const result = await service.get();

      expect(result).toEqual(EMPTY_REGISTRY);
      expect(logger.warn).toHaveBeenCalledWith(
        'Mandatory environment variables are not defined: $CHECLUSTER_CR_NAMESPACE',
      );
      expect(mockCoreV1Api.listNamespacedConfigMap).not.toHaveBeenCalled();
    });

    it('should return parsed registry from ConfigMap data', async () => {
      const registryData = {
        providers: [{ id: 'provider1', name: 'Provider 1' }],
        tools: [{ id: 'tool1', name: 'Tool 1' }],
        defaultAiProviders: ['provider1'],
      };

      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [
          {
            metadata: { name: 'ai-tool-registry' },
            data: {
              'registry.json': JSON.stringify(registryData),
            },
          } as V1ConfigMap,
        ],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(mockCoreV1Api.listNamespacedConfigMap).toHaveBeenCalledWith({
        namespace,
        labelSelector: AI_REGISTRY_LABEL_SELECTOR,
      });
      expect(result).toEqual(registryData);
    });

    it('should return empty registry when no ConfigMaps found', async () => {
      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(result).toEqual(EMPTY_REGISTRY);
    });

    it('should return empty registry when ConfigMap has no data', async () => {
      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [
          {
            metadata: { name: 'ai-tool-registry' },
            data: undefined,
          } as V1ConfigMap,
        ],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(result).toEqual(EMPTY_REGISTRY);
    });

    it('should skip ConfigMaps with undefined data', async () => {
      const registryData = {
        providers: [{ id: 'provider2', name: 'Provider 2' }],
        tools: [{ id: 'tool2', name: 'Tool 2' }],
        defaultAiProviders: ['provider2'],
      };

      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [
          {
            metadata: { name: 'empty-cm' },
            data: undefined,
          } as V1ConfigMap,
          {
            metadata: { name: 'ai-tool-registry' },
            data: {
              'registry.json': JSON.stringify(registryData),
            },
          } as V1ConfigMap,
        ],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(result).toEqual(registryData);
    });

    it('should throw error when API call fails', async () => {
      mockCoreV1Api.listNamespacedConfigMap.mockRejectedValueOnce(new Error('Forbidden'));

      await expect(service.get()).rejects.toThrow('Unable to list AI tool registry ConfigMap');
    });

    it('should handle invalid JSON in ConfigMap data and return empty registry', async () => {
      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [
          {
            metadata: { name: 'ai-tool-registry' },
            data: {
              'registry.json': 'not valid json{{{',
            },
          } as V1ConfigMap,
        ],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(logger.error).toHaveBeenCalledWith(
        expect.objectContaining({ message: expect.stringContaining('') }),
        'Failed to parse AI tool registry data: %s',
        'registry.json',
      );
      expect(result).toEqual(EMPTY_REGISTRY);
    });

    it('should handle missing arrays in parsed data and return empty arrays', async () => {
      const incompleteData = {
        providers: 'not-an-array',
        tools: null,
        // defaultAiProviders is missing entirely
      };

      mockCoreV1Api.listNamespacedConfigMap.mockResolvedValueOnce({
        items: [
          {
            metadata: { name: 'ai-tool-registry' },
            data: {
              'registry.json': JSON.stringify(incompleteData),
            },
          } as V1ConfigMap,
        ],
      } as V1ConfigMapList);

      const result = await service.get();

      expect(result).toEqual(EMPTY_REGISTRY);
    });
  });
});
